'use client';
import { useEffect, useState } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { useDebounce } from 'use-debounce';
import { HallType } from '@/types';
import SearchInput from '@/components/ui/SearchInput';
import NotFound from '@/components/ui/NotFound';
import HallCard from '@/components/ui/HallCard';
import { fetchHalls } from '@/api/halls';
import Pagination from '@/components/ui/Pagination';

const HallsPage = () => {
  const [halls, setHalls] = useState<HallType[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [debouncedQuery] = useDebounce(searchQuery, 300);
  const [currentPage, setCurrentPage] = useState(1); // حالة Pagination الجديدة
  const [totalPages, setTotalPages] = useState(0);
  const [totalItems, setTotalItems] = useState(0);
  const [hallsPerPage] = useState(3); // عدد الأحداث في كل صفحة
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchHalls(setLoading, currentPage, hallsPerPage, true).then((data) => {
      setHalls(data.halls);
      setTotalPages(data.totalPages);
      setTotalItems(data.totalItems);
    });
  }, [currentPage]);

  // 1. فلترة البيانات التجريبية بناءً على البحث
  const currentHall = (halls || []).filter(
    (hall) =>
      hall.name.toLowerCase().includes(debouncedQuery.toLowerCase()) ||
      hall.location.toLowerCase().includes(debouncedQuery.toLowerCase())
  );
  const paginate = (pageNumber: number) => setCurrentPage(pageNumber); // change page 

  useEffect(() => {
    setCurrentPage(1);
  }, [debouncedQuery]);
  return (
    <>
      {loading ? (
        <div className='flex items-center justify-center h-[70vh]'>
          <div className='animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-purple-500'></div>
        </div>
      ) : (
        <div className='p-6 space-y-6 bg-gradient-to-br from-blue-50 to-purple-50 min-h-screen'>
          {/* Search Input */}
          <div className='grid grid-cols-2 justify- items-center gap-4'>
            <SearchInput
              name='Hall'
              searchQuery={searchQuery}
              setSearchQuery={setSearchQuery}
              setCurrentPage={() => setCurrentPage(1)}
            />
          </div>
          {currentHall?.length > 0 ? (
            <>
              {' '}
              {/* Cards */}
              {loading ? (
                <div className='flex justify-center items-center min-h-[40vh]'>
                  <div className='animate-spin w-12 h-12 border-4 border-purple-500 border-t-transparent rounded-full'></div>
                </div>
              ) : (
                <div className='grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6'>
                  <AnimatePresence>
                    {currentHall?.map((hall, index) => (
                      <HallCard
                        key={index}
                        hall={hall}
                      />
                    ))}
                  </AnimatePresence>
                </div>
              )}
              {/* Pagination Controls */}
              {/* Pagination Controls */}
              {currentHall.length > 0 && (
                <Pagination
                  currentPage={currentPage}
                  totalPages={totalPages}
                  totalItems={totalItems}
                  paginate={paginate}
                />
              )}
            </>
          ) : (
            <NotFound message='The Hall are not found' />
          )}
        </div>
      )}
    </>
  );
};
export default HallsPage;
